import close from '../pics/close.png'
import{Routes} from 'react-router-dom'
const Sidebar = () => {
  return (
    <div className="sidebar">
      <img src={close} className='close' alt="" />
      <Routes></Routes>
    </div>
  )
}

export default Sidebar
